// Validate email format properly
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

const errors = [];
if (!$json.name || $json.name.trim() === '') {
  errors.push('Name is required');
}
if (!$json.email || !emailRegex.test($json.email)) {
  errors.push('Valid email is required');
}
if (!$json.subject || $json.subject.trim() === '') {
  errors.push('Subject is required');
}
if (!$json.message || $json.message.trim() === '') {
  errors.push('Message body is required');
}

if (errors.length > 0) {
  throw new Error(errors.join('; '));
}

return [{
  json: {
    ...$json,
    validation_passed: true
  }
}];

// Handle optional PDF attachment text if provided by upstream systems.
const attachment_filename = ($json.attachment_filename || '').trim();
const attachment_text = ($json.attachment_text || '').trim();

let processing_log = [];
let fulltext = $json.message || '';

if (attachment_filename) {
  if (attachment_text) {
    fulltext = `${fulltext}\n\n[Attachment: ${attachment_filename}]\n${attachment_text}`;
    processing_log.push('attachment_text_appended');
  } else {
    // Bonus requirement fallback: continue without attachment text if extraction failed/unavailable.
    processing_log.push(`attachment_present_but_no_text:${attachment_filename}`);
  }
}

return [{
  json: {
    ...$json,
    attachment_filename,
    attachment_text,
    fulltext,
    processing_log
  }
}];

const id = 'TCK-' + Date.now();

return [{
  json: {
    ...$json,
    ticket_id: id,
    timestamp: new Date().toISOString(),
    status: 'processing'
  }
}];

let classification;

function collectStrings(value, out) {
  if (value === null || value === undefined) return;
  if (typeof value === "string") {
    out.push(value);
    return;
  }
  if (Array.isArray(value)) {
    for (const item of value) collectStrings(item, out);
    return;
  }
  if (typeof value === "object") {
    for (const key of Object.keys(value)) collectStrings(value[key], out);
  }
}

try {
  const textCandidates = [];
  collectStrings($json, textCandidates);

  let parsed = null;
  let rawExtract = "";

  for (const candidate of textCandidates) {
    const match = String(candidate).match(/\{[\s\S]*\}/);
    if (!match) continue;

    try {
      parsed = JSON.parse(match[0]);
      rawExtract = match[0];
      break;
    } catch (e) {
      // Try next candidate
    }
  }

  if (!parsed) {
    throw new Error("No JSON object found in AI response");
  }

  classification = parsed;

  const required = ["category", "urgency", "sentiment", "confidence", "summary"];
  for (const field of required) {
    if (!(field in classification)) {
      throw new Error(`Missing required field: ${field}`);
    }
  }

  const validUrgencies = ["critical", "high", "medium", "low"];
  classification.urgency = String(classification.urgency || "").toLowerCase();

  if (!validUrgencies.includes(classification.urgency)) {
    throw new Error(`Invalid urgency: ${classification.urgency}`);
  }

  classification.category = String(classification.category || "other").toLowerCase();
  classification.sentiment = String(classification.sentiment || "neutral").toLowerCase();
  classification.confidence = Number(classification.confidence);

  if (
    Number.isNaN(classification.confidence) ||
    classification.confidence < 0 ||
    classification.confidence > 1
  ) {
    throw new Error(`Invalid confidence score: ${classification.confidence}`);
  }

  return [
    {
      json: {
        ...$json,
        ...classification,
        ai_validation_passed: true,
        ai_response_raw: rawExtract
      }
    }
  ];
} catch (e) {
  throw new Error(`AI Output Validation Error: ${e.message}`);
}

// Process Qdrant results and compute retrieval confidence.
const rawResults =
  ($json.result && $json.result.result) ||
  ($json.result && Array.isArray($json.result) ? $json.result : null) ||
  ($json.error ? [] : []);

const threshold = Number($env.RETRIEVAL_SCORE_THRESHOLD || 0.6);
const results = Array.isArray(rawResults) ? rawResults : [];
const knowledge_sources = [];
let knowledge_context = '';

if (results.length > 0) {
  knowledge_context = 'Relevant knowledge base articles:\n\n';
  for (let i = 0; i < results.length; i++) {
    const item = results[i] || {};
    const payload = item.payload || {};
    const source = payload.source || 'Unknown';
    const content = payload.content || '';
    const score = Number(item.score || 0);

    knowledge_sources.push({ source, score });
    knowledge_context += `[${i + 1}] Source: ${source} (Relevance: ${(score * 100).toFixed(1)}%)\n`;
    knowledge_context += `${String(content).substring(0, 350)}...\n\n`;
  }
} else {
  knowledge_context = 'No specific knowledge base articles found.';
}

const retrieval_score = knowledge_sources.length > 0 ? Number(knowledge_sources[0].score || 0) : 0;
const retrieval_low_confidence = retrieval_score < threshold;

const existingLog = Array.isArray($json.processing_log) ? $json.processing_log : [];
const processing_log = [
  ...existingLog,
  `knowledge_chunks:${knowledge_sources.length}`,
  `retrieval_score:${retrieval_score.toFixed(4)}`,
  `retrieval_low_confidence:${retrieval_low_confidence}`
];

return [{
  json: {
    ...$json,
    knowledge_context,
    knowledge_sources,
    retrieval_score,
    retrieval_low_confidence,
    processing_log
  }
}];

