const aiDraft = $json.message || $json.text || $json.output || $json.content || '';

let status = 'normal';
let needs_review = false;
if (Number($json.confidence || 0) < 0.6) {
  status = 'needs-manual-review';
  needs_review = true;
}

const existingLog = Array.isArray($json.processing_log) ? $json.processing_log : [];
const processing_log = [
  ...existingLog,
  `ai_confidence:${Number($json.confidence || 0).toFixed(4)}`,
  `status:${status}`
];

return [{
  json: {
    ...$json,
    status,
    needs_manual_review: needs_review,
    draft_response: aiDraft,
    processing_log
  }
}];

const processing_log = Array.isArray($json.processing_log) ? $json.processing_log.join(' | ') : '';

return [{
  json: {
    ticket_id: $json.ticket_id,
    timestamp: $json.timestamp,
    name: $json.name,
    email: $json.email,
    subject: $json.subject,
    category: $json.category,
    urgency: $json.urgency,
    sentiment: $json.sentiment,
    confidence: $json.confidence,
    ai_summary: $json.summary,
    draft_response: $json.draft_response,
    knowledge_sources: JSON.stringify($json.knowledge_sources || []),
    status: $json.status,
    processing_log
  }
}];
